const fs = require('fs');
const os = require('os');
const path = require('path');
const { test, expect } = require('@playwright/test');

const BASE = 'https://www.pixelssuite.com';

const URLS = {
  imageToPdf: `${BASE}/image-to-pdf`,
  pdfToWord: `${BASE}/pdf-to-word`,
  wordToPdf: `${BASE}/word-to-pdf`,
  pdfEditor: `${BASE}/pdf-editor`,
  resize: `${BASE}/resize-image`,
  bulkResize: `${BASE}/bulk-resize`,
  imageEnlarger: `${BASE}/image-enlarger`,
  cropPng: `${BASE}/crop-png`,
  cropJpg: `${BASE}/crop-jpg`,
  cropWebp: `${BASE}/crop-webp`,
  compress: `${BASE}/compress-image`,
  convertToJpg: `${BASE}/convert-to-jpg`,
  convertToPng: `${BASE}/convert-to-png`,
  convertToWebp: `${BASE}/convert-to-webp`,
  meme: `${BASE}/meme-generator`,
  colorPicker: `${BASE}/color-picker`,
  rotate: `${BASE}/rotate-image`,
  flip: `${BASE}/flip-image`,
  ocr: `${BASE}/image-to-text`,
};

/** Per-operation timeouts (ms) — avoid a single global 600000 ceiling. */
const MS = {
  nav: 45000,
  expectShort: 10000,
  expectMed: 30000,
  expectLong: 60000,
  download: 120000,
  /** Word→PDF WASM conversion can be slow on cold start. */
  wordPdfDownload: 180000,
  wordPdfTest: 210000,
};

function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) fs.mkdirSync(dirPath, { recursive: true });
}

function tmpPath(filename) {
  const dir = path.join(os.tmpdir(), 'pixelssuite-pw');
  ensureDir(dir);
  return path.join(dir, filename);
}

function writeFile(filePath, buffer) {
  ensureDir(path.dirname(filePath));
  fs.writeFileSync(filePath, buffer);
  return filePath;
}

// Tiny valid PNGs. (1x1 and 2x1)
const PNG_1X1 = Buffer.from(
  'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mP8/x8AAwMCAO+a7bQAAAAASUVORK5CYII=',
  'base64'
);
const PNG_2X1 = Buffer.from(
  'iVBORw0KGgoAAAANSUhEUgAAAAIAAAABCAQAAAD8fJRsAAAAC0lEQVR42mP8/x8AAwMCAO+a7bQAAAAASUVORK5CYII=',
  'base64'
);

// Tiny valid JPEG (1x1). Good enough for upload/convert tools.
const JPG_1X1 = Buffer.from(
  '',
  'base64'
);

/**
 * Minimal DOCX template.
 * This is a small, valid docx produced once and embedded as base64 to avoid extra deps.
 * It contains a short "Hello" paragraph.
 */
const DOCX_MINIMAL = Buffer.from(
  // eslint-disable-next-line max-len
  '',
  'base64'
);

async function gotoTool(page, url) {
  await page.goto(url, { waitUntil: 'networkidle', timeout: MS.nav });
  await expect(page).toHaveURL(new RegExp(url.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')));
}

async function clickFirstVisibleWordConversionButton(page) {
  const convertToPdf = page.locator('button', { hasText: /Convert to PDF/i });
  const convert = page.locator('button', { hasText: /Convert/i });
  const createPdf = page.locator('button', { hasText: /Create PDF/i });
  if (await convertToPdf.isVisible().catch(() => false)) return convertToPdf;
  if (await convert.isVisible().catch(() => false)) return convert;
  if (await createPdf.isVisible().catch(() => false)) return createPdf;
  return null;
}

/** Same flow as `pixelssuite_wordToPdf.spec.js` — avoids picking the wrong "Convert" in the shell. */
async function downloadPdfAfterWordUpload(page) {
  const downloadButton = page.locator('button', { hasText: /Download/i });
  const convertBtn = await clickFirstVisibleWordConversionButton(page);
  const dlMs = MS.wordPdfDownload;

  if (convertBtn) {
    try {
      const [download] = await Promise.all([page.waitForEvent('download', { timeout: dlMs }), convertBtn.click()]);
      return { filePath: await download.path(), suggestedFilename: download.suggestedFilename() };
    } catch {
      // Fall through: some builds show a Download button after Convert.
    }
  }

  await expect(downloadButton.first()).toBeVisible({ timeout: MS.expectMed });
  const [download] = await Promise.all([
    page.waitForEvent('download', { timeout: dlMs }),
    downloadButton.first().click(),
  ]);
  return { filePath: await download.path(), suggestedFilename: download.suggestedFilename() };
}

async function setFileInput(page, filePath, acceptFragment) {
  const input = page.locator('input[type="file"]').filter({ has: page.locator(`xpath=.`) }).first();
  const candidates = page.locator('input[type="file"]');
  const filtered = acceptFragment ? candidates.filter({ has: page.locator(`xpath=.`) }) : candidates;
  const byAccept = acceptFragment ? candidates.filter({ hasText: '' }) : candidates;
  // Prefer explicit accept match when provided, otherwise first file input.
  const loc = acceptFragment
    ? candidates.filter({ has: page.locator('xpath=.') }).first()
    : candidates.first();

  // The above "filters" are no-ops in some versions; keep it simple:
  const chosen = acceptFragment ? page.locator(`input[type="file"][accept*="${acceptFragment}"]`).first() : candidates.first();
  const finalInput = (await chosen.count()) ? chosen : input;

  await expect(finalInput).toBeAttached();
  await finalInput.setInputFiles(filePath);
}

async function uploadImage(page, filePath) {
  // Many tools accept image/*; some set accept="image/*" explicitly.
  const explicit = page.locator('input[type="file"][accept="image/*"]').first();
  const fallback = page.locator('input[type="file"]').first();
  const input = (await explicit.count()) ? explicit : fallback;
  await expect(input).toBeAttached();
  await input.setInputFiles(filePath);
}

async function uploadPdf(page, filePath) {
  const input = page.locator('input[type="file"][accept="application/pdf"], input[type="file"][accept*="pdf"]').first();
  await expect(input).toBeAttached();
  await input.setInputFiles(filePath);
}

async function uploadWord(page, filePath) {
  const input = page.locator('input[type="file"][accept*=".doc"], input[type="file"][accept*=".docx"], input[type="file"][accept*="wordprocessingml.document"]').first();
  await expect(input).toBeAttached();
  await input.setInputFiles(filePath);
}

async function waitForDownloadAfterClick(page, clickLocator, timeoutMs = MS.download) {
  const [download] = await Promise.all([
    page.waitForEvent('download', { timeout: timeoutMs }),
    clickLocator.click(),
  ]);
  const filePath = await download.path();
  expect(filePath).toBeTruthy();
  return { download, filePath, suggestedFilename: download.suggestedFilename() };
}

async function maybeDownloadOrError(page, actionLocator, errorRegex, timeoutMs = MS.download) {
  const downloadPromise = page.waitForEvent('download', { timeout: timeoutMs }).then((d) => ({ download: d })).catch(() => null);
  await actionLocator.click({ timeout: MS.expectMed });
  const result = await downloadPromise;
  if (result && result.download) {
    const filePath = await result.download.path();
    return { kind: 'download', filePath, suggestedFilename: result.download.suggestedFilename() };
  }
  const err = page.locator(`text=/${errorRegex.source}/${errorRegex.flags}`).first();
  await expect(err).toBeVisible({ timeout: MS.expectMed }).catch(() => null);
  return { kind: 'error' };
}

/** After file input, wait until the tool leaves the empty preview state. */
async function waitForImageToolReady(page) {
  await expect(page.getByText('No image yet.', { exact: true })).toBeHidden({ timeout: MS.expectLong });
}

/**
 * Compress Image tool: after upload the UI shows quality + Download (no separate "Compress" CTA;
 * the heading "Compress" is not a button — see error-context snapshots).
 */
async function compressThenDownload(page) {
  await waitForImageToolReady(page);
  const downloadBtn = page
    .locator('button', { hasText: /^Download$/i })
    .filter({ hasNotText: /Meme|Rotated/i })
    .first();
  await expect(downloadBtn).toBeVisible({ timeout: MS.expectLong });
  return waitForDownloadAfterClick(page, downloadBtn, MS.download);
}

/** Image converter: click "Convert" when present, then "Download". */
async function convertImageThenDownload(page) {
  await waitForImageToolReady(page);
  const convertBtn = page
    .locator('button')
    .filter({ hasText: /^Convert$/i })
    .filter({ hasNotText: /▾/ })
    .last();
  if (await convertBtn.isVisible().catch(() => false)) {
    await convertBtn.click();
  }
  const downloadBtn = page
    .locator('button', { hasText: /^Download$/i })
    .filter({ hasNotText: /Meme|Rotated/i })
    .first();
  await expect(downloadBtn).toBeVisible({ timeout: MS.expectLong });
  return waitForDownloadAfterClick(page, downloadBtn, MS.download);
}

function readPngDimensions(filePath) {
  const data = fs.readFileSync(filePath);
  const pngSignature = '89504e470d0a1a0a';
  expect(data.subarray(0, 8).toString('hex')).toBe(pngSignature);
  return {
    width: data.readUInt32BE(16),
    height: data.readUInt32BE(20),
  };
}

/** Resolve to test-data/sample.pdf if available; otherwise create via Playwright */
async function resolveSamplePdfPath(browser) {
  const testDataPdf = path.resolve(__dirname, '../test-data/sample.pdf');
  if (fs.existsSync(testDataPdf)) return testDataPdf;
  
  const pdfPath = tmpPath('sample.pdf');
  const page = await browser.newPage();
  await page.setContent('<html><body><h1>Hello PDF</h1><p>Edit me</p></body></html>');
  await page.pdf({ path: pdfPath, format: 'A4' });
  await page.close();
  return pdfPath;
}

function createSampleDocx() {
  return writeFile(tmpPath('sample.docx'), DOCX_MINIMAL);
}

/** Prefer checked-in Word/Doc samples; fall back to generated minimal DOCX. */
function resolveWordFixturePath() {
  const candidates = [
    path.resolve(__dirname, '../test-data/sample.docx'),
    path.resolve(__dirname, '../test-data/sample.doc'),
  ];
  const found = candidates.find((p) => fs.existsSync(p));
  if (found) return found;
  return createSampleDocx();
}

/** Resolve to test-data/sample.png if available; otherwise create minimal PNG */
function resolveSamplePngPath(name = 'sample.png') {
  const testDataPng = path.resolve(__dirname, '../test-data/sample.png');
  if (fs.existsSync(testDataPng)) return testDataPng;
  return writeFile(tmpPath(name), PNG_1X1);
}

/** Resolve to test-data/sample-wide.png if available; otherwise create 2x1 PNG */
function resolveSamplePngWidePath(name = 'sample-wide.png') {
  const testDataWide = path.resolve(__dirname, '../test-data/sample-wide.png');
  if (fs.existsSync(testDataWide)) return testDataWide;
  return writeFile(tmpPath(name), PNG_2X1);
}

/** Resolve to test-data/sample.jpg if available; otherwise create minimal JPG */
function resolveSampleJpgPath(name = 'sample.jpg') {
  const testDataJpg = path.resolve(__dirname, '../test-data/sample.jpg');
  if (fs.existsSync(testDataJpg)) return testDataJpg;
  return writeFile(tmpPath(name), JPG_1X1);
}

/** Resolve to test-data/sample.webp if available; otherwise create via PNG fallback */
function resolveSampleWebpPath(name = 'sample.webp') {
  const testDataWebp = path.resolve(__dirname, '../test-data/sample.webp');
  if (fs.existsSync(testDataWebp)) return testDataWebp;
  // Fallback: use sample.png if available
  const fallbackPng = path.resolve(__dirname, '../test-data/sample.png');
  if (fs.existsSync(fallbackPng)) return fallbackPng;
  return writeFile(tmpPath(name), PNG_1X1);
}

function createLargeFile(name, sizeBytes) {
  const filePath = tmpPath(name);
  ensureDir(path.dirname(filePath));
  const fd = fs.openSync(filePath, 'w');
  try {
    // Write zeros; most tools only validate size client-side.
    const chunk = Buffer.alloc(1024 * 1024, 0);
    let remaining = sizeBytes;
    while (remaining > 0) {
      const toWrite = Math.min(remaining, chunk.length);
      fs.writeSync(fd, chunk, 0, toWrite);
      remaining -= toWrite;
    }
  } finally {
    fs.closeSync(fd);
  }
  return filePath;
}

