test('TC006 - Image→PDF - Invalid format', async ({ page }) => {
  const bad = writeFile(tmpPath('tc006.txt'), Buffer.from('not an image'));
  await gotoTool(page, URLS.imageToPdf);
  await uploadImage(page, bad);

  const createPdf = page.getByRole('button', { name: /Create PDF/i });
  const result = await maybeDownloadOrError(page, createPdf, /failed|error|invalid|unsupported|try another file/i, 30000);
  expect(['download', 'error']).toContain(result.kind);
});

test('TC007 - Image→PDF - Large file (>20MB)', async ({ page }) => {
  const large = path.resolve(__dirname, '../test-data/large.jpg');
  if (!fs.existsSync(large)) {
    test.skip(`Large test image not found at ${large}`);
  }

  await gotoTool(page, URLS.imageToPdf);
  await uploadImage(page, large);
  const createPdf = page.getByRole('button', { name: /Create PDF/i });
  await expect(createPdf).toBeVisible();

  // Start waiting for download, but expect it to fail due to size limit
  const downloadPromise = page.waitForEvent('download', { timeout: 60000 }).catch(() => null);
  await createPdf.click();

  const download = await downloadPromise;
  if (download) {
    // If download happens, fail the test because large files should be rejected
    throw new Error('Large image file was converted to PDF, but site should reject files over 20MB');
  }

  // Expect an error message indicating file size limit
  const errorMessage = page.locator('text=/file too large|size limit|max 20MB|exceeds limit|too big/i').first();
  await expect(errorMessage).toBeVisible({ timeout: 60000 });
}, { timeout: 120000 });

