test('TC045 - Compress - Large file', async ({ page }) => {
  const large = createLargeFile('tc045-large.png', 21 * 1024 * 1024);
  await gotoTool(page, URLS.compress);
  await uploadImage(page, large);
  const blocked = page.getByText(/max 20MB|too large|20\s*MB|file size|not supported|invalid|error/i).first();
  const download = page.getByRole('button', { name: /^Download$/i }).first();
  await Promise.race([
    blocked.waitFor({ state: 'visible', timeout: MS.expectLong }).catch(() => null),
    download.waitFor({ state: 'visible', timeout: MS.expectLong }).catch(() => null),
  ]);
  const blockedVisible = await blocked.isVisible().catch(() => false);
  const downloadVisible = await download.isVisible().catch(() => false);
  expect(blockedVisible || !downloadVisible).toBeTruthy();
}, { timeout: 180000 });

